[CmdletBinding()] param ( [switch]$Force )
# Windows Configuration & Optimization Framework # Apply Debloat Profile (Tweaks/Apps/Apply_Debloat_Profile.ps1)
if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) { Write-Warning "This script requires Administrator privileges. Please run PowerShell as Admin." Exit }
$HelpersDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Helpers" Import-Module (Join-Path -Path $HelpersDir -ChildPath "Logging.psm1") -Force
Write-Host "=================================================" Write-Host " APPLY WINDOWS DEBLOAT PROFILE" -ForegroundColor Cyan Write-Host "=================================================" Write-Host "This profile removes sponsored bloatware (TikTok, Candy Crush)" Write-Host "and unnecessary default Microsoft apps (3D Viewer, Feedback Hub)." Write-Host "This cleans up the Start Menu and reclaims disk space." Write-Host "Press 'Y' to continue or any other key to abort..." if (-not $Force) { $Confirm = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown").Character } else { $Confirm = 'y' }
if ($Confirm -notmatch 'y') { Write-FrameworkLog -ModuleName "Apps" -Action "Aborted Debloat Profile Deployment" Write-Host "`nAborted by user." Exit }
Write-FrameworkLog -ModuleName "Apps" -Action "Starting Master Debloat Orchestrator" -Level WARNING
$ScriptDir = $PSScriptRoot
Write-Host "`n[1/2] Removing Sponsored Bloatware..." -ForegroundColor Cyan & (Join-Path -Path $ScriptDir -ChildPath "Remove_Sponsored_Apps.ps1") -Force:$Force
Write-Host "`n[2/2] Removing Unnecessary Microsoft Apps..." -ForegroundColor Cyan & (Join-Path -Path $ScriptDir -ChildPath "Remove_Unnecessary_MS_Apps.ps1") -Force:$Force
Write-FrameworkLog -ModuleName "Apps" -Action "Completed Master Debloat Orchestrator" -Level WARNING
Write-Host "`n[SUCCESS] Debloat Profile deployment complete!" -ForegroundColor Green if (-not $Force) { if (-not $Force) { Write-Host "Press any key to exit..." if (-not $Force) { $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown") } } }

[CmdletBinding()]
param (
    [switch]$Force
)

# Windows Configuration & Optimization Framework
# Disable Audio Enhancements (Tweaks/Audio/Disable_Audio_Enhancements.ps1)

if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Write-Warning "This script requires Administrator privileges. Please run PowerShell as Admin."
    Exit
}

$HelpersDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Helpers"
Import-Module (Join-Path -Path $HelpersDir -ChildPath "Logging.psm1") -Force
$SnapshotDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Restore\Audio"

if (-not (Test-Path $SnapshotDir)) { New-Item -Path $SnapshotDir -ItemType Directory -Force | Out-Null }

Write-Host "================================================="
Write-Host "   AUDIO ENHANCEMENTS MANAGER (LATENCY FIX)" -ForegroundColor Cyan
Write-Host "================================================="
Write-Host "Windows and Audio Drivers (like Realtek) often inject 'Signal"
Write-Host "Enhancements' (APOs) that add artificial latency and color the"
Write-Host "sound. Disabling these is critical for pure audio delivery."
Write-Host "================================================="
Write-Host "1. Disable All Audio Enhancements (Recommended for Latency/Purity)"
Write-Host "2. Enable Audio Enhancements (Default)"
Write-Host "3. Abort"
Write-Host "================================================="
$Choice = Read-Host "Select an option [1-3]"

if ($Choice -notmatch '^[1-2]$') {
    Write-FrameworkLog -ModuleName "Audio" -Action "Aborted Audio Enhancements config"
    Write-Host "`nAborted by user."
    Exit
}

Write-Host "`nScanning for Audio Endpoints..." -ForegroundColor Yellow
$RenderPath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\MMDevices\Audio\Render"
$CapturePath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\MMDevices\Audio\Capture"

# Function to toggle DisableProtectedAudioDG and DisableSysFx
function Toggle-Enhancements {
    param([string]$KeyPath, [int]$Value)
    
    if (Test-Path $KeyPath) {
        $Devices = Get-ChildItem -Path $KeyPath
        foreach ($Device in $Devices) {
            $FxProperties = Join-Path -Path $Device.PSPath -ChildPath "FxProperties"
            if (Test-Path $FxProperties) {
                # Backup the specific FX key if disabling
                if ($Value -eq 1) {
                    $BackupFile = Join-Path -Path $SnapshotDir -ChildPath "AudioFX_$($Device.PSChildName)_$(Get-Date -Format 'yyyyMMdd_HHmmss').reg"
                    $RegPathClean = $FxProperties -replace "::", "" -replace "Microsoft.PowerShell.Core\\Registry::", ""
                    & reg export $RegPathClean $BackupFile /y 2>$null | Out-Null
                }

                # Set DisableSysFx (commonly {1da5d803-d492-4edd-8c23-e0c0ffee7f0e},5)
                # Just loop through known property keys that disable effects
                $Props = Get-Item -Path $FxProperties
                foreach ($PropName in $Props.Property) {
                    if ($PropName -match "1da5d803-d492-4edd-8c23-e0c0ffee7f0e") {
                        Set-ItemProperty -Path $FxProperties -Name $PropName -Value $Value -Type DWord -Force -ErrorAction SilentlyContinue
                    }
                }
            }
        }
    }
}

if ($Choice -eq '1') {
    Write-Host "Disabling enhancements on Output devices..." -ForegroundColor Yellow
    Toggle-Enhancements -KeyPath $RenderPath -Value 1
    Write-Host "Disabling enhancements on Input devices..." -ForegroundColor Yellow
    Toggle-Enhancements -KeyPath $CapturePath -Value 1
    
    Write-FrameworkLog -ModuleName "Audio" -Action "Disabled Audio Enhancements globally"
    Write-Host "`n[SUCCESS] Audio Enhancements are DISABLED." -ForegroundColor Green
} else {
    Write-Host "Enabling enhancements on Output devices..." -ForegroundColor Yellow
    Toggle-Enhancements -KeyPath $RenderPath -Value 0
    Write-Host "Enabling enhancements on Input devices..." -ForegroundColor Yellow
    Toggle-Enhancements -KeyPath $CapturePath -Value 0

    Write-FrameworkLog -ModuleName "Audio" -Action "Enabled Audio Enhancements globally"
    Write-Host "`n[SUCCESS] Audio Enhancements are ENABLED." -ForegroundColor Green
}

Write-Host "Please restart the Windows Audio service or reboot to apply changes." -ForegroundColor Yellow


$null = Read-Host "Press Enter to exit..."

[CmdletBinding()] param ( [switch]$Force )
# Windows Configuration & Optimization Framework # Exclusive Mode Manager (Tweaks/Audio/Exclusive_Mode_Manager.ps1)
if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) { Write-Warning "This script requires Administrator privileges. Please run PowerShell as Admin." Exit }
$HelpersDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Helpers" Import-Module (Join-Path -Path $HelpersDir -ChildPath "Logging.psm1") -Force $SnapshotDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Restore\Audio"
if (-not (Test-Path $SnapshotDir)) { New-Item -Path $SnapshotDir -ItemType Directory -Force | Out-Null }
Write-Host "=================================================" Write-Host " WASAPI EXCLUSIVE MODE MANAGER" -ForegroundColor Cyan Write-Host "=================================================" Write-Host "WASAPI Exclusive Mode allows applications (games, DAWs)" Write-Host "to bypass the Windows audio mixer, communicating directly" Write-Host "with the audio driver for the lowest possible latency." Write-Host "=================================================" Write-Host "1. Enable Exclusive Mode (Recommended for Gamers/Producers)" Write-Host "2. Disable Exclusive Mode (Forces all audio through Windows Mixer)" Write-Host "3. Abort" Write-Host "=================================================" $Choice = Read-Host "Select an option [1-3]"
if ($Choice -notmatch '^[1-2]$') { Write-FrameworkLog -ModuleName "Audio" -Action "Aborted Exclusive Mode config" Write-Host "`nAborted by user." Exit }
Write-Host "`nScanning for Audio Endpoints..." -ForegroundColor Yellow $RenderPath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\MMDevices\Audio\Render" $CapturePath = "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\MMDevices\Audio\Capture"
function Toggle-ExclusiveMode { param([string]$KeyPath, [int]$Value)
if (Test-Path $KeyPath) { $Devices = Get-ChildItem -Path $KeyPath foreach ($Device in $Devices) { $Properties = Join-Path -Path $Device.PSPath -ChildPath "Properties" if (Test-Path $Properties) { # Property {b3f8fa53-0004-438e-9003-51a46e139bfc},3 corresponds to "Allow applications to take exclusive control of this device" # Property {b3f8fa53-0004-438e-9003-51a46e139bfc},4 corresponds to "Give exclusive mode applications priority"
Set-ItemProperty -Path $Properties -Name "{b3f8fa53-0004-438e-9003-51a46e139bfc},3" -Value $Value -Type DWord -Force -ErrorAction SilentlyContinue Set-ItemProperty -Path $Properties -Name "{b3f8fa53-0004-438e-9003-51a46e139bfc},4" -Value $Value -Type DWord -Force -ErrorAction SilentlyContinue } } } }
if ($Choice -eq '1') { Write-Host "Enabling Exclusive Mode on Output devices..." -ForegroundColor Yellow Toggle-ExclusiveMode -KeyPath $RenderPath -Value 1 Write-Host "Enabling Exclusive Mode on Input devices..." -ForegroundColor Yellow Toggle-ExclusiveMode -KeyPath $CapturePath -Value 1
Write-FrameworkLog -ModuleName "Audio" -Action "Enabled WASAPI Exclusive Mode" Write-Host "`n[SUCCESS] Exclusive Mode is ENABLED." -ForegroundColor Green } else { Write-Host "Disabling Exclusive Mode on Output devices..." -ForegroundColor Yellow Toggle-ExclusiveMode -KeyPath $RenderPath -Value 0 Write-Host "Disabling Exclusive Mode on Input devices..." -ForegroundColor Yellow Toggle-ExclusiveMode -KeyPath $CapturePath -Value 0
Write-FrameworkLog -ModuleName "Audio" -Action "Disabled WASAPI Exclusive Mode" Write-Host "`n[SUCCESS] Exclusive Mode is DISABLED." -ForegroundColor Red }
Write-Host "Please restart the Windows Audio service or reboot to apply changes." -ForegroundColor Yellow
$null = Read-Host "Press Enter to exit..."

# ==============================================================================
# SCRIPT: Manage Background Apps
# TARGET SYSTEM: Windows 10 & Windows 11
# DESCRIPTION: Manages Windows background applications behavior. 
#              Provides global disabling/enabling of background app activity
#              as well as granular control for individual Microsoft Store/UWP apps.
# SAFETY LEVEL: Safe & Fully Reversible
# ==============================================================================

$Host.UI.RawUI.WindowTitle = "Windows Background Apps Manager"

$GlobalReg = "HKCU:\Software\Microsoft\Windows\CurrentVersion\BackgroundAccessApplications"
$ConsentReg = "HKCU:\Software\Microsoft\Windows\CurrentVersion\CapabilityAccessManager\ConsentStore\backgroundTasks"

# Ensure global key exists
if (-not (Test-Path $GlobalReg)) {
    New-Item -Path $GlobalReg -Force | Out-Null
}
# Ensure consent key exists
if (-not (Test-Path $ConsentReg)) {
    New-Item -Path $ConsentReg -Force | Out-Null
}

function Clear-Console {
    Clear-Host
    Write-Host "======================================================================" -ForegroundColor Cyan
    Write-Host "                      WINDOWS BACKGROUND APPS MANAGER                 " -ForegroundColor Cyan
    Write-Host "======================================================================" -ForegroundColor Cyan
    Write-Host ""
}

function Check-GlobalStatus {
    $val = Get-ItemProperty -Path $GlobalReg -Name "GlobalUserDisabled" -ErrorAction SilentlyContinue
    if ($val -and $val.GlobalUserDisabled -eq 1) {
        return "DISABLED (All background apps blocked)"
    } else {
        return "ENABLED (Background apps permitted globally)"
    }
}

while ($true) {
    Clear-Console
    $globalStatus = Check-GlobalStatus
    Write-Host "[*] Current Global Background Status: $globalStatus" -ForegroundColor Yellow
    Write-Host ""
    Write-Host "Choose an option:" -ForegroundColor White
    Write-Host "  1. Turn OFF Background Activity Globally (Recommended for max performance)" -ForegroundColor Green
    Write-Host "  2. Turn ON Background Activity Globally (Windows Default)" -ForegroundColor Gray
    Write-Host "  3. Manage Individual App Background Permissions" -ForegroundColor White
    Write-Host "  4. Exit" -ForegroundColor Red
    Write-Host ""

    $choice = Read-Host "Option (1-4)"

    switch ($choice) {
        "1" {
            try {
                Set-ItemProperty -Path $GlobalReg -Name "GlobalUserDisabled" -Value 1 -Type DWord -Force | Out-Null
                Write-Host ""
                Write-Host "[+] All background applications have been disabled globally!" -ForegroundColor Green
                Write-Host "    Note: Individual settings will be overridden by this global block." -ForegroundColor Gray
            } catch {
                Write-Host "[!] Error: Failed to update global registry settings." -ForegroundColor Red
            }
            Start-Sleep -Seconds 2
        }

        "2" {
            try {
                # Set to 0 or remove
                Remove-ItemProperty -Path $GlobalReg -Name "GlobalUserDisabled" -ErrorAction SilentlyContinue
                Write-Host ""
                Write-Host "[+] Background applications re-enabled globally!" -ForegroundColor Green
                Write-Host "    Note: Individual app permissions will now be respected." -ForegroundColor Gray
            } catch {
                Write-Host "[!] Error: Failed to update global registry settings." -ForegroundColor Red
            }
            Start-Sleep -Seconds 2
        }

        "3" {
            while ($true) {
                Clear-Console
                Write-Host "Scanning installed Windows Store/UWP packages..." -ForegroundColor Gray

                # Fetch packages
                $packages = Get-AppxPackage -User ([System.Security.Principal.WindowsIdentity]::GetCurrent().Name) | 
                            Select-Object Name, PackageFamilyName -Unique | 
                            Sort-Object Name

                Write-Host "=== Individual App Background Permissions ===" -ForegroundColor Cyan
                Write-Host "    (Note: Denying background permissions keeps the app from running when closed)" -ForegroundColor Gray
                Write-Host ""

                $index = 1
                $appList = @()
                foreach ($pkg in $packages) {
                    # Skip system-critical packages if they are too basic
                    if ($pkg.Name -like "*Framework*" -or $pkg.Name -like "*Runtime*") { continue }

                    # Get current individual status from CapabilityAccessManager
                    $appRegPath = "$ConsentReg\$($pkg.PackageFamilyName)"
                    $status = "Allow (Default)"
                    if (Test-Path $appRegPath) {
                        $val = Get-ItemProperty -Path $appRegPath -Name "Value" -ErrorAction SilentlyContinue
                        if ($val) { $status = $val.Value }
                    }

                    $statusColor = "Green"
                    if ($status -eq "Deny") { $statusColor = "Red" }

                    Write-Host -NoNewline "  [$index] $($pkg.Name) " -ForegroundColor White
                    Write-Host -NoNewline "--> Current State: " -ForegroundColor Gray
                    Write-Host $status -ForegroundColor $statusColor

                    $appList += [PSCustomObject]@{
                        Index = $index
                        Name = $pkg.Name
                        Family = $pkg.PackageFamilyName
                        Status = $status
                    }
                    $index++
                }

                Write-Host ""
                $select = Read-Host "Select app number to toggle Deny/Allow (or 'q' to go back)"
                if ($select -eq "q") { break }

                $match = $appList | Where-Object { $_.Index -eq $select }
                if ($match) {
                    $appRegPath = "$ConsentReg\$($match.Family)"
                    if (-not (Test-Path $appRegPath)) {
                        New-Item -Path $appRegPath -Force | Out-Null
                    }

                    $newVal = "Deny"
                    if ($match.Status -eq "Deny") {
                        $newVal = "Allow"
                    }

                    try {
                        Set-ItemProperty -Path $appRegPath -Name "Value" -Value $newVal -Type String -Force | Out-Null
                        Write-Host ""
                        Write-Host "[+] Successfully set $($match.Name) background permission to: $newVal" -ForegroundColor Green
                        Start-Sleep -Seconds 1
                    } catch {
                        Write-Host "[!] Error: Failed to modify app settings in registry." -ForegroundColor Red
                        Start-Sleep -Seconds 2
                    }
                } else {
                    Write-Host "Invalid selection." -ForegroundColor Red
                    Start-Sleep -Seconds 1
                }
            }
        }

        "4" {
            Write-Host "Exiting..." -ForegroundColor Cyan
            break
        }
    }
}

[CmdletBinding()]
param (
    [switch]$Force
)

# Windows Configuration & Optimization Framework
# Detect Slow Startup Apps (Tweaks/Boot/Detect_Slow_Startup_Apps.ps1)

if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Write-Warning "This script requires Administrator privileges. Please run PowerShell as Admin."
    Exit
}

Write-Host "================================================="
Write-Host "   STARTUP APPLICATION ANALYZER" -ForegroundColor Cyan
Write-Host "================================================="
Write-Host "Querying all active startup hooks from the registry..."
Write-Host "=================================================`n"

$Paths = @(
    "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Run",
    "HKLM:\SOFTWARE\Wow6432Node\Microsoft\Windows\CurrentVersion\Run",
    "HKCU:\Software\Microsoft\Windows\CurrentVersion\Run"
)

$StartupApps = @()

foreach ($Path in $Paths) {
    if (Test-Path $Path) {
        $Key = Get-Item -Path $Path
        foreach ($ValueName in $Key.Property) {
            $ValueData = (Get-ItemProperty -Path $Path -Name $ValueName).$ValueName
            $StartupApps += [PSCustomObject]@{
                Name = $ValueName
                Command = $ValueData
                Scope = if ($Path -match "HKLM") { "System-Wide" } else { "Current User" }
            }
        }
    }
}

if ($StartupApps.Count -eq 0) {
    Write-Host "No traditional startup applications found in Run keys." -ForegroundColor Green
} else {
    $StartupApps | Format-Table -AutoSize
}

Write-Host "`nWARNING: The following apps are known to severely delay boot times:" -ForegroundColor Yellow
Write-Host "- Adobe Creative Cloud / Acrobat Update Services"
Write-Host "- RGB/Hardware Software (iCUE, Armoury Crate, Razer Synapse)"
Write-Host "- Game Launchers (Steam, Epic, EA) set to start automatically"
Write-Host "- Third-party Antivirus (McAfee, Norton)"

Write-Host "`nRecommendation: Open Task Manager (Ctrl+Shift+Esc), go to the" -ForegroundColor Cyan
Write-Host "'Startup Apps' tab, and disable everything except your critical audio/GPU drivers."

Write-Host "`nPress any key to exit..."
if (-not $Force) { $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown") }

# Windows Configuration & Optimization Framework # Generate Boot Trace (Tweaks/Boot/Generate_Boot_Trace.ps1)
