$HelpersDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Helpers" Import-Module (Join-Path -Path $HelpersDir -ChildPath "Logging.psm1") -Force $BackupRoot = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Restore\Drivers"
