[CmdletBinding()] param ( [switch]$Force )
# Windows Configuration & Optimization Framework # Apply Laptop Battery Profile (Tweaks/Power/Apply_Laptop_Battery_Profile.ps1)
if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) { Write-Warning "This script requires Administrator privileges. Please run PowerShell as Admin." Exit }
$HelpersDir = Join-Path -Path $PSScriptRoot -ChildPath "..\..\Core\Helpers" Import-Module (Join-Path -Path $HelpersDir -ChildPath "Logging.psm1") -Force
Write-Host "=================================================" Write-Host " APPLY LAPTOP BATTERY PROFILE" -ForegroundColor Green Write-Host "=================================================" Write-Host "This profile configures your system to preserve battery life and thermals." Write-Host "It enables hibernation, sets the Balanced power plan, and allows" Write-Host "USB devices to sleep when not in use." Write-Host "Press 'Y' to continue or any other key to abort..." if (-not $Force) { $Confirm = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown").Character } else { $Confirm = 'y' }
if ($Confirm -notmatch 'y') { Write-FrameworkLog -ModuleName "Power" -Action "Aborted Laptop Battery Profile Deployment" Write-Host "`nAborted by user." Exit }
Write-FrameworkLog -ModuleName "Power" -Action "Starting Master Laptop Battery Orchestrator" -Level WARNING
