Write-Host "`n[2/3] Setting Balanced Power Plan..." -ForegroundColor Cyan # 381b4222-f694-41d0-9685-ff5bb260df2e is the standard GUID for Balanced powercfg /setactive 381b4222-f694-41d0-9685-ff5bb260df2e Write-FrameworkLog -ModuleName "Power" -Action "Enabled Balanced Power Plan" -OldValue "Unknown" -NewValue "381b4222-f694-41d0-9685-ff5bb260df2e"
Write-Host "`n[3/3] Enabling USB Selective Suspend (battery saving)..." -ForegroundColor Cyan powercfg /SETACVALUEINDEX SCHEME_CURRENT 2a737441-1930-4402-8d77-b2bea1222653 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 1 powercfg /SETDCVALUEINDEX SCHEME_CURRENT 2a737441-1930-4402-8d77-b2bea1222653 48e6b7a6-50f5-4782-a5d4-53bb8f07e226 1 powercfg /S SCHEME_CURRENT Write-FrameworkLog -ModuleName "Power" -Action "Enabled USB Selective Suspend" -OldValue "Unknown" -NewValue "1"
Write-FrameworkLog -ModuleName "Power" -Action "Completed Master Laptop Battery Orchestrator" -Level WARNING
Write-Host "`n[SUCCESS] Laptop Battery Profile deployment complete!" -ForegroundColor Green if (-not $Force) { if (-not $Force) { Write-Host "Press any key to exit..." if (-not $Force) { $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown") } } }

# ======================================================================== # WinAurex - OPTIMIZE SERVICES TWEAK # ======================================================================== # Enforces service states via Service Control Manager (SCM) to bypass # strict registry key ACLs and permissions issues. # ========================================================================
# Check for Administrator privileges if (-not ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) { Write-Warning "This script must be run as Administrator! Please relaunch an elevated console." Exit }
$services = @{ "WbioSrvc" = "Disabled" "FontCache" = "Disabled" "FontCache3.0.0.0" = "Disabled" "GraphicsPerfSvc" = "Disabled" "stisvc" = "Disabled" "WerSvc" = "Disabled" "PcaSvc" = "Disabled" "Wecsvc" = "Disabled" "DiagTrack" = "Disabled" "GpuEnergyDrv" = "Disabled" "WSearch" = "Disabled" "ShellHWDetection" = "Disabled" "ssh-agent" = "Disabled" "diagsvc" = "Disabled" "DPS" = "Disabled" }
Write-Output "========================================================================" Write-Output " APPLYING SERVICES OPTIMIZATION" Write-Output "========================================================================"
foreach ($service in $services.Keys) { if (Get-Service -Name $service -ErrorAction SilentlyContinue) { Write-Host "Configuring: [ $service ] -> $($services[$service])" -ForegroundColor Cyan Stop-Service -Name $service -Force -ErrorAction SilentlyContinue Set-Service -Name $service -StartupType $services[$service] -ErrorAction SilentlyContinue } else { Write-Host "Configuring: [ $service ] -> NOT DETECTED (Skipping)" -ForegroundColor Yellow } }
Write-Output "========================================================================" Write-Output " SERVICES OPTIMIZATION APPLIED" Write-Output "========================================================================"
Read-Host -Prompt "Press Enter to exit"

